/* ── Ripple Button ── */
function RippleBtn({children, href, onClick, style={}, target, rel}){
  const [ripples,setRipples] = useState([]);
  const ref = useRef(null);
  function handleClick(e){
    const rect = ref.current.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;
    const id = Date.now();
    setRipples(r => [...r,{x,y,id}]);
    setTimeout(()=>setRipples(r=>r.filter(rp=>rp.id!==id)),700);
    if(onClick) onClick(e);
  }
  const inner = <span style={{position:"relative",zIndex:1,display:"flex",alignItems:"center",gap:6,justifyContent:"center"}}>{children}</span>;
  const common = {position:"relative",overflow:"hidden",cursor:"pointer",...style};
  if(href) return (
    <a ref={ref} href={href} target={target} rel={rel} onClick={handleClick} style={{...common,textDecoration:"none",display:"inline-flex",alignItems:"center",justifyContent:"center"}}>
      {inner}
      {ripples.map(r=><span key={r.id} style={{position:"absolute",left:r.x-50,top:r.y-50,width:100,height:100,borderRadius:"50%",background:"rgba(255,255,255,0.3)",animation:"ripple 0.7s ease-out forwards",pointerEvents:"none"}}/>)}
    </a>
  );
  return (
    <button ref={ref} onClick={handleClick} style={{...common,border:"none",display:"inline-flex",alignItems:"center",justifyContent:"center"}}>
      {inner}
      {ripples.map(r=><span key={r.id} style={{position:"absolute",left:r.x-50,top:r.y-50,width:100,height:100,borderRadius:"50%",background:"rgba(255,255,255,0.3)",animation:"ripple 0.7s ease-out forwards",pointerEvents:"none"}}/>)}
    </button>
  );
}

/* ── Custom Cursor ── */
function CustomCursor(){
  const dot = useRef(null);
  const ring = useRef(null);
  const pos = useRef({x:0,y:0});
  const ringPos = useRef({x:0,y:0});
  const [clicking, setClicking] = useState(false);
  const [hovering, setHovering] = useState(false);

  useEffect(()=>{
    function onMove(e){
      pos.current = {x:e.clientX, y:e.clientY};
      if(dot.current){
        dot.current.style.left = e.clientX + "px";
        dot.current.style.top  = e.clientY + "px";
      }
    }
    function onDown(){ setClicking(true); }
    function onUp(){ setClicking(false); }
    function checkHover(e){
      const el = document.elementFromPoint(e.clientX,e.clientY);
      const isHoverable = el && (el.tagName==="A"||el.tagName==="BUTTON"||el.closest("a")||el.closest("button"));
      setHovering(!!isHoverable);
    }
    window.addEventListener("mousemove", onMove);
    window.addEventListener("mousemove", checkHover);
    window.addEventListener("mousedown", onDown);
    window.addEventListener("mouseup", onUp);

    let raf;
    function animate(){
      ringPos.current.x += (pos.current.x - ringPos.current.x)*0.12;
      ringPos.current.y += (pos.current.y - ringPos.current.y)*0.12;
      if(ring.current){
        ring.current.style.left = ringPos.current.x + "px";
        ring.current.style.top  = ringPos.current.y + "px";
      }
      raf = requestAnimationFrame(animate);
    }
    animate();
    return ()=>{
      window.removeEventListener("mousemove",onMove);
      window.removeEventListener("mousemove",checkHover);
      window.removeEventListener("mousedown",onDown);
      window.removeEventListener("mouseup",onUp);
      cancelAnimationFrame(raf);
    };
  },[]);

  return <>
    {/* Dot */}
    <div ref={dot} style={{
      position:"fixed", pointerEvents:"none", zIndex:9999,
      width: clicking ? 6 : 8, height: clicking ? 6 : 8,
      borderRadius:"50%", background:"#06b6d4",
      transform:"translate(-50%,-50%)",
      transition:"width 0.1s,height 0.1s",
      mixBlendMode:"difference",
    }}/>
    {/* Ring */}
    <div ref={ring} style={{
      position:"fixed", pointerEvents:"none", zIndex:9998,
      width: hovering ? 48 : clicking ? 24 : 32,
      height: hovering ? 48 : clicking ? 24 : 32,
      borderRadius:"50%",
      border: hovering ? "2px solid #8b5cf6" : "1.5px solid rgba(6,182,212,0.6)",
      transform:"translate(-50%,-50%)",
      transition:"width 0.25s,height 0.25s,border-color 0.25s",
      background: hovering ? "rgba(139,92,246,0.08)" : "transparent",
    }}/>
  </>;
}

/* ── Nav ── */
function NavBar(){
  const [scrolled,setScrolled]=useState(false);
  useEffect(()=>{
    const h=()=>setScrolled(window.scrollY>40);
    window.addEventListener("scroll",h);
    return()=>window.removeEventListener("scroll",h);
  },[]);
  return(
    <nav style={{
      position:"fixed",top:0,left:0,right:0,zIndex:200,
      background:scrolled?"rgba(10,10,10,0.93)":"transparent",
      backdropFilter:scrolled?"blur(18px)":"none",
      borderBottom:scrolled?"1px solid rgba(255,255,255,0.06)":"none",
      padding:"1rem 4vw",display:"flex",alignItems:"center",justifyContent:"space-between",
      transition:"all 0.3s",
    }}>
      <span style={{fontWeight:800,fontSize:17,color:"#fff",letterSpacing:0.5}}>Sai Rupesh</span>
      <div style={{display:"flex",gap:"2rem"}}>
        {NAV_LINKS.map(l=>(
          <a key={l} href={`#${l.toLowerCase()}`} style={{color:"#9ca3af",textDecoration:"none",fontSize:14,transition:"color 0.2s"}}
            onMouseEnter={e=>e.target.style.color="#fff"}
            onMouseLeave={e=>e.target.style.color="#9ca3af"}
          >{l}</a>
        ))}
      </div>
      <RippleBtn href="#contact" style={{
        padding:"9px 22px",background:"#fff",color:"#000",
        borderRadius:8,fontSize:13,fontWeight:700,
        transition:"transform 0.15s,box-shadow 0.15s",
      }}
        onMouseEnter={e=>{e.currentTarget.style.transform="scale(1.05)";e.currentTarget.style.boxShadow="0 0 18px rgba(255,255,255,0.25)";}}
        onMouseLeave={e=>{e.currentTarget.style.transform="scale(1)";e.currentTarget.style.boxShadow="none";}}
      >Hire Me</RippleBtn>
    </nav>
  );
}

